exercises.starter_code:
// Write your ProfileCard class below
// Use class-level static variables for the profile data
// Define the 4 helper methods plus main

exercises.expected_solution:
public class ProfileCard {
    // Class-level data (static variables)
    static String name = "Priya Sharma";
    static String username = "priya_codes";
    static String title = "Backend Developer";
    static int yearsExperience = 3;
    static int repos = 47;
    static int followers = 1284;

    public static void main(String[] args) {
        printBorder();
        printNameSection();
        printBorder();
        printProfessionalInfo();
        printBorder();
        printStats();
        printBorder();
    }

    public static void printBorder() {
        System.out.println("+----------------------------------+");
    }

    public static void printNameSection() {
        System.out.println("Name: " + name);
        System.out.println("@" + username);
    }

    public static void printProfessionalInfo() {
        System.out.println("Title: " + title);
        System.out.println("Experience: " + yearsExperience + " years");
    }

    public static void printStats() {
        System.out.println("Repos: " + repos);
        System.out.println("Followers: " + followers);
    }
}
